wl() { [ $# -lt 2 ] && { echo "Usage: wl <filename> <text>"; return 1; }; local filename="$1"; shift; local text="$*"; local dir=$(dirname "$filename"); [ ! -d "$dir" ] && { echo "Error: Directory '$dir' does not exist"; return 1; }; [ -e "$filename" ] && [ ! -w "$filename" ] && { echo "Error: Cannot write to '$filename' (permission denied)"; return 1; }; echo "$text" >> "$filename" && echo "Successfully appended '$text' to '$filename'" || { echo "Error: Failed to append to '$filename'"; return 1; }; }